import json

def solve(event_json):
    event = json.loads(event_json)
    payload = event["payload"]
    op = payload["op"]
    table = payload["source"]["table"]
    if op in ("c", "r"):
        fields = sorted(payload["after"].keys())
    elif op == "u":
        before = payload.get("before", {})
        after = payload["after"]
        fields = sorted(k for k in after if before.get(k) != after[k])
    elif op == "d":
        fields = sorted(payload["before"].keys())
    else:
        fields = []
    return json.dumps({"op": op, "table": table, "fields": fields})
